const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string>(HOME_PAGE_ID);
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(true);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Persistence State
  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('theme') as Theme) || 'dark';
  });
  const [fontSize, setFontSize] = useState<FontSize>(() => {
    return (localStorage.getItem('fontSize') as FontSize) || 'medium';
  });
  const [accentColor, setAccentColor] = useState<AccentColor>(() => {
    return (localStorage.getItem('accentColor') as AccentColor) || 'indigo';
  });

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  // Initial Notifications (Cleaned of Forum references)
  useEffect(() => {
    const initialNotifications: Notification[] = [
        { id: '1', title: 'تحديث جديد', message: 'تم إضافة مادة "محاسبة حكومية" للمنصة.', type: 'info', timestamp: Date.now() - 3600000, read: false },
    ];
    if (notifications.length === 0) {
        setNotifications(initialNotifications);
    }
  }, []);

  const handleMarkAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  };

  const handleClearNotifications = () => {
      setNotifications([]);
  };

  // Apply Theme Effect
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Persist Font Size
  useEffect(() => {
    localStorage.setItem('fontSize', fontSize);
  }, [fontSize]);

  // Apply Accent Color
  useEffect(() => {
    const root = document.documentElement;
    const palette = COLOR_PALETTES[accentColor];

    // Inject CSS variables for primary color
    Object.entries(palette).forEach(([shade, value]) => {
      root.style.setProperty(`--color-primary-${shade}`, value as string);
    });

    localStorage.setItem('accentColor', accentColor);
  }, [accentColor]);

  // Determine global font size class
  const getFontSizeClass = () => {
    switch (fontSize) {
      case 'small': return 'text-sm';
      case 'large': return 'text-lg';
      case 'medium':
      default: return 'text-base';
    }
  };


  useEffect(() => {
    // Check for a logged-in user in local storage on initial load
    const storedUser = localStorage.getItem('fintechUser');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
  }, []);

  const handleLogin = (name: string, picture: string | null) => {
    if (!name.trim()) return;

    const mockUser: User = {
      id: Date.now().toString(),
      name: name,
      picture: picture || `https://i.pravatar.cc/150?u=${encodeURIComponent(name)}`,
    };
    localStorage.setItem('fintechUser', JSON.stringify(mockUser));
    setUser(mockUser);
  };

  const handleLogout = () => {
    localStorage.removeItem('fintechUser');
    setUser(null);
    setSelectedCourseId(HOME_PAGE_ID); // Reset to home page on logout
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUser(updatedUser);
    localStorage.setItem('fintechUser', JSON.stringify(updatedUser));
  };


  if (!user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  const selectedCourse = COURSES.find(c => c.id === selectedCourseId) as Course | undefined;

  return (
    <div className={`flex h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-gray-100 font-sans transition-all duration-300 ${getFontSizeClass()}`}>
      <Sidebar
        user={user}
        onLogout={handleLogout}
        onUpdateUser={handleUpdateUser}
        courses={COURSES}
        selectedCourseId={selectedCourseId}
        setSelectedCourseId={setSelectedCourseId}
        isExpanded={isSidebarExpanded}
        setIsExpanded={setIsSidebarExpanded}
        onOpenSettings={() => setIsSettingsOpen(true)}
        notifications={notifications}
        onMarkNotificationAsRead={handleMarkAsRead}
        onClearNotifications={handleClearNotifications}
      />
      <main className="flex-1 overflow-y-auto transition-all duration-300 flex flex-col">
        <div className="flex-1">
          {selectedCourse ? (
            <CourseHub key={selectedCourse.id} course={selectedCourse} userName={user.name} />
          ) : (
            <HomePage 
              onSelectCourse={setSelectedCourseId} 
              userName={user.name} 
            />
          )}
        </div>

        {/* Footer Added Below */}
        <footer className="py-6 px-4 text-center border-t border-gray-200 dark:border-gray-800 bg-white/50 dark:bg-gray-900/50 backdrop-blur-sm">
          <p className="text-sm text-gray-500 dark:text-gray-400 font-medium">
            تم التطوير بواسطة <span className="text-primary-600 dark:text-primary-400 font-bold">Dev Lido</span>
          </p>
        </footer>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        theme={theme}
        setTheme={setTheme}
        fontSize={fontSize}
        setFontSize={setFontSize}
        accentColor={accentColor}
        setAccentColor={setAccentColor}
      />
    </div>
  );
};

export default App;

