          `;
      }

      const fullSystemPrompt = `${courseSystemPrompt}\n\n${knowledgeInstruction}\n\nUser name is: ${userName}. Your name is "Bakkar" (بكار). You are a smart, friendly, and enthusiastic AI tutor for commerce students. You speak in a helpful, encouraging tone, sometimes using Egyptian colloquialisms if appropriate to sound natural like the character Bakkar, but keep the academic content accurate and professional. Address the user by name occasionally.\n\nDEVELOPER INFO: The developer of this platform is "Lido" (المطور ليدو). If anyone asks who developed, created, or built the platform, or who is the developer, or asks "مين المطور؟" always say that the developer is Lido (المطور ليدو) and nothing else regarding attribution.\n\nIMPORTANT: Do not use Markdown formatting (like **bold** or *italic*). Do not use asterisks (*) in your response. Output plain text only.`;

      const responseText = await generateChatResponse(input, messages, fullSystemPrompt, chatMode, verbosity);
      const modelMessage: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: responseText };
      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      console.error("Error generating response:", error);
      const errorMessage: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: "عفواً، حصل خطأ. ممكن تجرب تاني." };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePlayTTS = async (text: string) => {
    if (isPlaying) return;
    try {
        // Strip asterisks for speech as well
        const cleanText = text.replace(/\*/g, '');
        const audioContent = await generateSpeech(cleanText);
        playAudio(audioContent);
    } catch (error) {
        console.error("Error generating speech:", error);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-gray-800 rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700 overflow-hidden">
      <div className="bg-white dark:bg-gray-800 p-4 border-b border-gray-100 dark:border-gray-700 shadow-sm z-10">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
             <div className="flex items-center gap-3">
                 <div className="relative">
                    <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-primary-100 shadow-lg shadow-primary-500/20">
                        <img 
                            src="https://avatar.iran.liara.run/public/boy?username=Bakkar" 
                            alt="Bakkar" 
                            className="w-full h-full object-cover"
                        />
                    </div>
                    <div className="absolute -bottom-1 -right-1 bg-green-500 w-4 h-4 rounded-full border-2 border-white dark:border-gray-800"></div>
                 </div>
                 <div>
                    <h3 className="text-xl font-bold text-gray-900 dark:text-white leading-tight">بكار الذكي</h3>
                    <p className="text-xs text-primary-600 dark:text-primary-400 font-medium">مساعدك الشخصي في المادة</p>
                 </div>
             </div>

            <div className="flex items-center gap-2 overflow-x-auto pb-1 md:pb-0 no-scrollbar">
                {/* Model Mode Group */}
                <div className="bg-gray-100 dark:bg-gray-700/50 rounded-xl p-1 flex items-center">
                    <ModeToggle label="عادي" icon={<IconSparkles className="h-3.5 w-3.5" />} mode="standard" currentMode={chatMode} setMode={setChatMode} />
                    <ModeToggle label="سريع" icon={<IconBolt className="h-3.5 w-3.5" />} mode="fast" currentMode={chatMode} setMode={setChatMode} />
                    <ModeToggle label="تفكير" icon={<IconBrain className="h-3.5 w-3.5" />} mode="thinking" currentMode={chatMode} setMode={setChatMode} />
                </div>

                {/* Divider */}
                <div className="w-px h-8 bg-gray-200 dark:bg-gray-700 hidden md:block"></div>

                {/* Verbosity Group */}
                <div className="bg-gray-100 dark:bg-gray-700/50 rounded-xl p-1 flex items-center">
                    <VerbosityToggle value="concise" label="مختصر" icon={<IconShortText className="h-3.5 w-3.5" />} current={verbosity} set={setVerbosity} />
                    <VerbosityToggle value="balanced" label="متوازن" icon={<IconScale className="h-3.5 w-3.5" />} current={verbosity} set={setVerbosity} />
                    <VerbosityToggle value="detailed" label="مفصل" icon={<IconLongText className="h-3.5 w-3.5" />} current={verbosity} set={setVerbosity} />
                </div>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50 dark:bg-gray-900/20">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex items-start gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            {msg.role === 'model' && (
                <div className="flex-shrink-0 h-8 w-8 rounded-full overflow-hidden bg-primary-100 border border-primary-200 shadow-sm">
                     <img 
                        src="https://avatar.iran.liara.run/public/boy?username=Bakkar" 
                        alt="Bakkar" 
                        className="w-full h-full object-cover"
                    />
                </div>
            )}

            <div className={`max-w-md p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? 'bg-primary-600 text-white rounded-tr-none' : 'bg-white dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded-tl-none border border-gray-100 dark:border-gray-600'}`}>
              <p className="text-sm leading-relaxed" style={{ whiteSpace: 'pre-wrap' }}>
                {msg.text.replace(/\*/g, '')}
              </p>
              {msg.role === 'model' && msg.id !== 'init' && (
                <div className="mt-2 flex items-center justify-end border-t border-gray-100 dark:border-gray-600 pt-2 gap-2">
                    <button 
                        onClick={() => handlePlayTTS(msg.text)} 
                        disabled={isPlaying} 
                        className="p-1.5 text-gray-400 dark:text-gray-400 hover:text-primary-600 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-gray-600 rounded-lg disabled:opacity-50 transition-all"
                        title="قراءة الرد صوتياً"
                    >
                        <IconSound className="h-4 w-4" />
                    </button>
                </div>
              )}
            </div>

            {msg.role === 'user' && <div className="flex-shrink-0 h-8 w-8 rounded-full bg-gray-200 dark:bg-gray-600 flex items-center justify-center overflow-hidden"><IconUser className="h-5 w-5 text-gray-500 dark:text-gray-300" /></div>}
          </div>
        ))}
        {isLoading && (
            <div className="flex items-start gap-3">
                <div className="flex-shrink-0 h-8 w-8 rounded-full overflow-hidden bg-primary-100 border border-primary-200">
                    <img 
                        src="https://avatar.iran.liara.run/public/boy?username=Bakkar" 
                        alt="Bakkar" 
                        className="w-full h-full object-cover"
                    />
                </div>
                <div className="p-4 rounded-2xl rounded-tl-none bg-white dark:bg-gray-700 flex items-center gap-3 border border-gray-100 dark:border-gray-600 shadow-sm">
                    <div className="flex space-x-1">
                        <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                    </div>
                    <span className="text-sm text-gray-400 font-medium">بكار بيفكر...</span>
                </div>
            </div>
        )}
        <div ref={chatEndRef} />
      </div>
      <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-100 dark:border-gray-700">
        <form onSubmit={handleSendMessage} className="flex items-center gap-3 relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="اسأل بكار أي حاجة..."
            className="flex-1 py-3 px-4 bg-gray-100 dark:bg-gray-700/50 border-transparent focus:border-primary-500 focus:bg-white dark:focus:bg-gray-700 rounded-xl text-gray-900 dark:text-white focus:ring-2 focus:ring-primary-500/20 focus:outline-none transition-all shadow-inner"
            disabled={isLoading}
          />
          <button type="submit" disabled={isLoading || !input.trim()} className="p-3 bg-gradient-to-r from-primary-600 to-primary-500 text-white rounded-xl disabled:from-gray-400 disabled:to-gray-500 hover:shadow-lg hover:shadow-primary-500/30 transition-all duration-200 transform hover:scale-105 active:scale-95">
            <IconSend className="h-5 w-5 transform rotate-180" />
          </button>
        </form>
      </div>
    </div>
  );
};

interface ModeToggleProps {
    label: string;
    icon: React.ReactNode;
    mode: ChatMode;
    currentMode: ChatMode;
    setMode: (mode: ChatMode) => void;
}

const ModeToggle: React.FC<ModeToggleProps> = ({ label, icon, mode, currentMode, setMode }) => (
    <button 
        onClick={() => setMode(mode)} 
        className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold rounded-lg transition-all duration-200 ${
            currentMode === mode 
            ? 'bg-white dark:bg-gray-600 text-primary-600 dark:text-white shadow-sm ring-1 ring-black/5 dark:ring-white/10' 
            : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-200/50 dark:hover:bg-gray-600/50'
        }`} 
        title={label}
    >
        {icon}
        <span className="hidden sm:inline">{label}</span>
    </button>
);

interface VerbosityToggleProps {
    label: string;
    icon: React.ReactNode;
    value: Verbosity;
    current: Verbosity;
    set: (v: Verbosity) => void;
}

const VerbosityToggle: React.FC<VerbosityToggleProps> = ({ label, icon, value, current, set }) => (
    <button 
        onClick={() => set(value)} 
        className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold rounded-lg transition-all duration-200 ${
            current === value 
            ? 'bg-white dark:bg-gray-600 text-primary-600 dark:text-white shadow-sm ring-1 ring-black/5 dark:ring-white/10' 
            : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-200/50 dark:hover:bg-gray-600/50'
        }`} 
        title={label}
    >
        {icon}
        <span className="hidden sm:inline">{label}</span>
    </button>
);

import React, { useState, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createBlob, decode, decodeAudioData } from '../utils/audioUtils';
import { IconMicrophone, IconStop, IconLoader, IconUser, IconSparkles } from './icons';

interface Transcript {
    id: number;
    speaker: 'user' | 'model';
    text: string;
}

interface LiveConversationProps {
    userName: string;
    courseName: string;
    knowledgeBase?: string;
}

type VoiceGender = 'male' | 'female';

export const LiveConversation: React.FC<LiveConversationProps> = ({ userName, courseName, knowledgeBase }) => {
    const [isLive, setIsLive] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [transcripts, setTranscripts] = useState<Transcript[]>([]);
    const [selectedVoice, setSelectedVoice] = useState<VoiceGender>('male');

    const sessionPromiseRef = useRef<Promise<any> | null>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const nextStartTimeRef = useRef<number>(0);

    let currentInputTranscription = '';
    let currentOutputTranscription = '';

    const startConversation = async () => {
        if (isLive) return;

        setTranscripts([]);
        setError(null);
        setIsLoading(true);

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
            // FIX: Cast window to any to support webkitAudioContext for older browsers.
            outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            nextStartTimeRef.current = 0;

            // Voice Configuration
            // Puck: Male
            // Kore: Female
            const voiceName = selectedVoice === 'male' ? 'Puck' : 'Kore';
            const assistantName = selectedVoice === 'male' ? 'بكار' : 'سارة';

            // Addressing logic: Bakkar talks to males, Sara talks to females (based on user request)
            const addressInstruction = selectedVoice === 'male' 
                ? "Address the user in the masculine form (صيغة المذكر)." 
                : "Address the user in the feminine form (صيغة المؤنث) ONLY. Use feminine verbs and adjectives (e.g، عاملة إيه، فاهمة، جاهزة).";

            const initialGreeting = selectedVoice === 'male'
                ? `"ازيك يا ${userName}، أقدر أساعدك إزاي في مادة ${courseName}؟"`
                : `"ازيك يا ${userName}، عاملة إيه؟ أقدر أساعدك إزاي في مادة ${courseName}؟"`;

            let knowledgeInstruction = "";
            if (knowledgeBase) {
                knowledgeInstruction = `
                USE THE FOLLOWING KNOWLEDGE BASE AS YOUR PRIMARY SOURCE OF TRUTH for answering questions. 
                Knowledge Base:
                ${knowledgeBase}
                `;
            }

            const systemInstruction = `
            You are a smart, friendly, and helpful AI tutor named ${assistantName}.
            IMPORTANT: Speak ONLY in the Common Egyptian Colloquial Dialect (Ammiya Masri). 
            Do NOT use Standard Arabic (Fusha) at all. Be natural, like a native Egyptian friend.
            The user's name is "${userName}".
            The current subject we are discussing is "${courseName}".
            ${addressInstruction}
            ${knowledgeInstruction}

            DEVELOPER INFO: The developer of this platform is "Lido" (المطور ليدو). If anyone asks who developed, created, or built the platform, or who is the developer, always say that the developer is Lido (المطور ليدو).

            When the conversation starts, your VERY FIRST sentence MUST be exactly:
            ${initialGreeting}

            Keep your responses concise, engaging, and relevant to the subject.
            IMPORTANT: Do not use asterisks (*) or markdown formatting in your response.
            `;

            sessionPromiseRef.current = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } }
                    },
                    systemInstruction: systemInstruction,
                },
                callbacks: {
                    onopen: () => {
                        console.log('Live session opened.');
                        setIsLoading(false);
                        setIsLive(true);

                        // Send a silent text trigger to force the model to speak the greeting defined in system instruction
                        sessionPromiseRef.current?.then(session => {
                            session.sendRealtimeInput({
                                content: [{ role: 'user', parts: [{ text: "Hello, start the conversation now." }] }]
                            });
                        });
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        // Handle audio output
                        const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (base64Audio && outputAudioContextRef.current) {
                            const audioCtx = outputAudioContextRef.current;
                            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, audioCtx.currentTime);
                            const audioBuffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
                            const source = audioCtx.createBufferSource();
                            source.buffer = audioBuffer;
                            source.connect(audioCtx.destination);
                            source.start(nextStartTimeRef.current);
                            nextStartTimeRef.current += audioBuffer.duration;
                        }

                        // Handle transcriptions
                        if (message.serverContent?.inputTranscription) {
                            currentInputTranscription += message.serverContent.inputTranscription.text;
                        }
                        if (message.serverContent?.outputTranscription) {
                            currentOutputTranscription += message.serverContent.outputTranscription.text;
                        }
                        if (message.serverContent?.turnComplete) {
                            const userInput = currentInputTranscription.trim();
                            const modelOutput = currentOutputTranscription.trim();

                            setTranscripts(prev => {
                                let newTranscripts = [...prev];
                                if (userInput) newTranscripts.push({ id: Date.now(), speaker: 'user', text: userInput });
                                if (modelOutput) newTranscripts.push({ id: Date.now() + 1, speaker: 'model', text: modelOutput.replace(/\*/g, '') });
                                return newTranscripts;
                            });

                            currentInputTranscription = '';
                            currentOutputTranscription = '';
                        }
                    },
                    onerror: (e: ErrorEvent) => {
                        console.error('Live error:', e);
                        setError('حصل خطأ أثناء المحادثة.');
                        stopConversation();
                    },
                    onclose: (e: CloseEvent) => {
                        console.log('Live session closed.');
                    }
                }
            });

            // FIX: Cast window to any to support webkitAudioContext for older browsers.
            inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            const source = inputAudioContextRef.current.createMediaStreamSource(stream);
            scriptProcessorRef.current = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);

            scriptProcessorRef.current.onaudioprocess = (event) => {
                const inputData = event.inputBuffer.getChannelData(0);
                const pcmBlob = createBlob(inputData);
                sessionPromiseRef.current?.then((session) => {
                    session.sendRealtimeInput({ media: pcmBlob });
                });
            };

            source.connect(scriptProcessorRef.current);
            scriptProcessorRef.current.connect(inputAudioContextRef.current.destination);

        } catch (err) {
            console.error('Failed to start conversation:', err);
            setError('مشكلة في الوصول للمايكروفون. اتأكد من السماحيات.');
            setIsLoading(false);
        }
    };

    const stopConversation = useCallback(async () => {
        if (!isLive && !isLoading) return;

        setIsLive(false);
        setIsLoading(false);

        scriptProcessorRef.current?.disconnect();
        inputAudioContextRef.current?.close();
        outputAudioContextRef.current?.close();

        sessionPromiseRef.current?.then(session => session.close());
        sessionPromiseRef.current = null;
    }, [isLive, isLoading]);

    return (
        <div className="max-w-2xl mx-auto p-4 bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700">
            <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">محادثة صوتية حية</h2>
            <p className="text-gray-600 dark:text-gray-400 mb-6">ابدأ محادثة صوتية فورية باللهجة المصرية. اختار الصوت المناسب ليك.</p>

            <div className="flex flex-col items-center gap-6 mb-6">
                 {/* Voice Selection */}
                 <div className="bg-gray-100 dark:bg-gray-700 p-1.5 rounded-lg inline-flex">
                    <button
                        onClick={() => setSelectedVoice('male')}
                        disabled={isLive || isLoading}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                            selectedVoice === 'male' 
                            ? 'bg-white dark:bg-gray-600 text-primary-600 dark:text-white shadow-sm' 
                            : 'text-gray-500 dark:text-gray-400 hover:text-gray-900'
                        } disabled:opacity-50`}
                    >
                        صوت ولد (بكار)
                    </button>
                    <button
                        onClick={() => setSelectedVoice('female')}
                        disabled={isLive || isLoading}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                            selectedVoice === 'female' 
                            ? 'bg-white dark:bg-gray-600 text-pink-600 dark:text-pink-300 shadow-sm' 
                            : 'text-gray-500 dark:text-gray-400 hover:text-gray-900'
                        } disabled:opacity-50`}
                    >
                        صوت بنت (سارة)
                    </button>
                 </div>

                 <button
                    onClick={isLive ? stopConversation : startConversation}
                    disabled={isLoading}
                    className={`flex items-center justify-center w-24 h-24 rounded-full text-white transition-all duration-300 ease-in-out focus:outline-none focus:ring-4 focus:ring-offset-2 focus:ring-offset-gray-100 dark:focus:ring-offset-gray-800
                        ${isLive ? 'bg-red-600 hover:bg-red-700 animate-pulse shadow-red-500/50' : 'bg-primary-600 hover:bg-primary-700 shadow-primary-500/50 shadow-lg'}
                        ${isLoading ? 'bg-gray-500 cursor-not-allowed' : ''}`}
                >
                    {isLoading ? <IconLoader className="h-10 w-10" /> : (isLive ? <IconStop className="h-10 w-10" /> : <IconMicrophone className="h-10 w-10" />) }
                </button>
            </div>

            <div className="bg-gray-50 dark:bg-gray-900/50 rounded-lg p-4 min-h-[250px] max-h-[400px] overflow-y-auto border border-gray-200 dark:border-gray-700">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-semibold text-gray-900 dark:text-white">نص المحادثة</h3>
                    <span className="text-xs px-2 py-1 bg-primary-100 dark:bg-primary-900 text-primary-700 dark:text-primary-300 rounded">
                        {selectedVoice === 'male' ? 'لهجة مصرية (بكار)' : 'لهجة مصرية (سارة)'}
                    </span>
                </div>

                {error && <p className="text-sm text-red-400 mb-2">{error}</p>}

                <div className="space-y-4">
                    {transcripts.length === 0 && !isLive && (
                        <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                            <p>اضغط على المايك عشان تبدأ الكلام مع المساعد الذكي</p>
                        </div>
                    )}
                    {transcripts.map(t => (
                        <div key={t.id} className={`flex items-start gap-3 ${t.speaker === 'user' ? 'justify-end' : 'justify-start'}`}>
                            {t.speaker === 'model' && (
                                <div className={`flex-shrink-0 h-8 w-8 rounded-full flex items-center justify-center overflow-hidden bg-gray-100 border border-gray-200`}>
                                     <img 
                                        src={selectedVoice === 'male' ? "https://avatar.iran.liara.run/public/boy?username=Bakkar" : "https://avatar.iran.liara.run/public/girl?username=Sara"} 
                                        alt={selectedVoice === 'male' ? "Bakkar" : "Sara"}
                                        className="w-full h-full object-cover"
                                    />
                                </div>
                            )}
                            <div className={`p-3 rounded-2xl text-sm max-w-[80%] ${
                                t.speaker === 'user' 
                                ? 'bg-primary-600 text-white rounded-tr-none' 
                                : 'bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-200 shadow-sm border border-gray-100 dark:border-gray-600 rounded-tl-none'
                            }`}>
                                {t.text}
                            </div>
                             {t.speaker === 'user' && <div className="flex-shrink-0 h-8 w-8 rounded-full bg-gray-300 dark:bg-gray-600 flex items-center justify-center"><IconUser className="h-5 w-5 text-gray-700 dark:text-white" /></div>}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};
